password = #{password,jdbcType=VARCHAR}, nickname = #{nickname,jdbcType=VARCHAR}, avatar = #{avatar,jdbcType=VARCHAR}, birthday = #{birthday,jdbcType=DATE}, background_img = #{backgroundImg,jdbcType=VARCHAR}, phone = #{phone,jdbcType=VARCHAR}, sex = #{sex,jdbcType=TINYINT}, status = #{status,jdbcType=TINYINT}, introduction = #{introduction,jdbcType=VARCHAR}, update_time = #{updateTime,jdbcType=TIMESTAMP}, deleted = #{deleted,jdbcType=BOOLEAN}
